                seen[named] = true;
                // possibly cyclic until proven otherwise
                var namedʗ1 = named;
                var seenʗ1 = seen;
                defer(() => {
                    seenʗ1[namedʗ1] = varSized;
                });
            }
        }
        // record final determination for named
        var switchᴛ4 = under(t);
        switch (switchᴛ4.type()) {
        case ж<Array> u: {
            varSized = hasVarSize((~u).elem, seen); return;
        }
        case ж<Struct> u: {
